// Aggregate all vendor payments due into ONE digest message.
// Replaces the per-PO splitOut that fanned out into ~4 sends per PO
// (Finance / Vinodh / Sridhar / Vivek-high-value-cc) — easily hundreds
// of messages on a busy day, blowing Meta's burst rate-limit.
const rows = $input.first().json;
const pos = Array.isArray(rows) ? rows : (rows.data ?? []);
if (!pos.length) {
  // Empty array — output nothing so downstream Send nodes don't fire.
  return [];
}

const total = pos.length;
const totalOutstanding = pos.reduce((s, p) => s + Number(p.amount_outstanding || 0), 0);
const totalLakhs = (totalOutstanding / 100000).toFixed(1);

const HIGH_VALUE_THRESHOLD = 500000;
const highValuePos = pos.filter(p => Number(p.amount_outstanding || 0) >= HIGH_VALUE_THRESHOLD);
const msmePos = pos.filter(p => p.vendor_is_msme);

const formatPo = (p) => {
  const vendor = (p.vendor_name || 'Unknown').slice(0, 25);
  const amt = (Number(p.amount_outstanding || 0) / 100000).toFixed(1);
  const due = (p.payment_due_date || '').slice(5); // MM-DD
  const flags = [
    Number(p.amount_outstanding || 0) >= HIGH_VALUE_THRESHOLD ? '🚨' : '',
    p.vendor_is_msme ? 'MSME' : '',
  ].filter(Boolean).join(' ');
  return `${vendor} ₹${amt}L (${due}${flags ? ` ${flags}` : ''})`;
};

const MAX_INLINE = 8;
const inline = pos.slice(0, MAX_INLINE).map(formatPo).join(' · ');
const more = total > MAX_INLINE ? ` · +${total - MAX_INLINE} more` : '';

const flagsLine = [
  highValuePos.length > 0 ? `🚨 ${highValuePos.length} high-value (>₹5L)` : '',
  msmePos.length > 0 ? `🔔 ${msmePos.length} MSME (45-day window)` : '',
].filter(Boolean).join(' · ');

const title = `💸 *Vendor payments due (7d)* — ${total} PO${total === 1 ? '' : 's'} · ₹${totalLakhs}L outstanding`;
const body = `${inline}${more}${flagsLine ? ` · ${flagsLine}` : ''} · Open ERP /purchase to schedule.`;

return [{
  json: {
    to_phone_finance: process.env.FINANCE_HEAD_WHATSAPP || '',
    to_phone_vinodh: process.env.VINODH_WHATSAPP || '',
    to_phone_sridhar: process.env.SRIDHAR_WHATSAPP || '',
    title,
    body: body.slice(0, 900),
    total_count: total,
    high_value_count: highValuePos.length,
  },
}];
